const items = $input.all();
const ticker = $("Normalize Ticker").first().json.ticker || "AAPL";
let newsContext = "";
let articleCount = 0;

try {
  if (items && items.length > 0 && items[0].json) {
    const rawText = items[0].json.data || items[0].json.body || JSON.stringify(items[0].json);
    const titleMatches = [...rawText.matchAll(/<title>(.*?)<\/title>/g)];
    const descMatches = [...rawText.matchAll(/<description>(.*?)<\/description>/g)];

    const articles = [];
    for (let i = 1; i < Math.min(titleMatches.length, 11); i++) {
      const title = (titleMatches[i]?.[1] || "").replace(/<!\[CDATA\[|\]\]>/g, "").replace(/<[^>]*>?/gm, "").trim();
      const desc = (descMatches[i]?.[1] || "").replace(/<!\[CDATA\[|\]\]>/g, "").replace(/<[^>]*>?/gm, "").trim();
      if (title) {
        articles.push(`Article ${i}: ${title}\nSummary: ${desc}`);
      }
    }

    if (articles.length > 0) {
      articleCount = articles.length;
      newsContext = articles.join("\n\n");
    }
  }
} catch (err) {
  // Gracefully catch XML/parsing errors
}

if (!newsContext || newsContext.trim().length === 0) {
  newsContext = `No active RSS news headlines retrieved for ticker ${ticker}. Evaluating based on fundamental quantitative ratios, revenue growth trends, profit margins, cost structure control, and competitive moat metrics for ${ticker}.`;
}

return [{
  json: {
    ticker: ticker,
    articleCount: articleCount,
    newsContext: newsContext
  }
}];

const item = $input.first().json;
let reportText = item.choices?.[0]?.message?.content || item.message?.content || item.text || item.output || item.response || "";

if (typeof reportText === 'object') {
  reportText = JSON.stringify(reportText);
}

return [{
  json: {
    ticker: $("Normalize Ticker").first().json.ticker || "AAPL",
    report: reportText,
    status: "success"
  }
}];
